from dataclasses import dataclass
from typing import Literal

SkillType = Literal["ml_engineer", "data_engineer", "platform_engineer",
                    "product_manager", "ux_designer", "qa_engineer"]

@dataclass
class TeamMember:
    name: str
    skill_type: SkillType
    availability_pct: float   # 0.0–1.0 (1.0 = full-time on project work)

@dataclass
class QuarterCapacity:
    quarter: str              # e.g. "2026-Q3"
    team_members: list[TeamMember]
    quarter_weeks: int = 13
    leave_buffer_pct: float = 0.15     # public holidays + planned leave
    support_allocation_pct: float = 0.20  # BAU support, on-call, bugs
    innovation_allocation_pct: float = 0.10  # team upskilling, spikes

    def gross_person_weeks(self) -> float:
        return sum(m.availability_pct * self.quarter_weeks for m in self.team_members)

    def net_person_weeks(self) -> float:
        """Person-weeks available for new project delivery."""
        deductions = self.leave_buffer_pct + self.support_allocation_pct + self.innovation_allocation_pct
        return self.gross_person_weeks() * (1 - deductions)

    def net_by_skill(self) -> dict[SkillType, float]:
        deductions = self.leave_buffer_pct + self.support_allocation_pct + self.innovation_allocation_pct
        result: dict[str, float] = {}
        for m in self.team_members:
            result[m.skill_type] = result.get(m.skill_type, 0) + m.availability_pct * self.quarter_weeks * (1 - deductions)
        return result

# Example: a cross-functional GenAI squad
q3_capacity = QuarterCapacity(
    quarter="2026-Q3",
    team_members=[
        TeamMember("Alice",   "ml_engineer",       1.0),
        TeamMember("Bob",     "ml_engineer",       0.8),   # 20 % on another team
        TeamMember("Carol",   "data_engineer",     1.0),
        TeamMember("Dave",    "platform_engineer", 1.0),
        TeamMember("Eve",     "product_manager",   0.5),   # shared PM
        TeamMember("Frank",   "qa_engineer",       1.0),
    ],
)

print(q3_capacity.gross_person_weeks())   # 52.0
print(q3_capacity.net_person_weeks())     # 52.0 × (1 - 0.45) = 28.6
print(q3_capacity.net_by_skill())
# {'ml_engineer': 9.9, 'data_engineer': 7.15, 'platform_engineer': 7.15,
#  'product_manager': 3.6, 'qa_engineer': 7.15}

from dataclasses import dataclass, field

@dataclass
class PortfolioSlot:
    request_id: str
    priority_score: float
    estimate: ProjectEstimate
    is_mandatory: bool = False   # regulatory mandates skip capacity check

@dataclass
class PortfolioPlan:
    quarter: str
    committed: list[PortfolioSlot] = field(default_factory=list)
    deferred: list[PortfolioSlot] = field(default_factory=list)
    net_capacity_used_pw: float = 0.0
    net_capacity_available_pw: float = 0.0

    @property
    def utilisation_pct(self) -> float:
        if self.net_capacity_available_pw == 0:
            return 0.0
        return self.net_capacity_used_pw / self.net_capacity_available_pw * 100

def build_portfolio_plan(
    demand: list[PortfolioSlot],         # pre-sorted by priority_score descending
    capacity: QuarterCapacity,
    target_utilisation: float = 0.75,    # fill to 75 % of net capacity
) -> PortfolioPlan:
    net_pw = capacity.net_person_weeks()
    budget_pw = net_pw * target_utilisation
    plan = PortfolioPlan(
        quarter=capacity.quarter,
        net_capacity_available_pw=net_pw,
    )
    # Mandatory items first (regulatory mandates, hard-deadline items)
    for slot in [s for s in demand if s.is_mandatory]:
        plan.committed.append(slot)
        plan.net_capacity_used_pw += slot.estimate.expected_pw()

    remaining = budget_pw - plan.net_capacity_used_pw
    for slot in [s for s in demand if not s.is_mandatory]:
        cost = slot.estimate.expected_pw()
        if cost <= remaining:
            plan.committed.append(slot)
            plan.net_capacity_used_pw += cost
            remaining -= cost
        else:
            plan.deferred.append(slot)

    return plan

def check_skill_feasibility(
    plan: PortfolioPlan,
    capacity: QuarterCapacity,
) -> dict[str, dict]:
    """
    Returns per-skill utilisation. Flag any skill over 90 % of net capacity.
    """
    net_by_skill = capacity.net_by_skill()
    demand_by_skill: dict[str, float] = {}
    for slot in plan.committed:
        for skill, pw in slot.estimate.skill_breakdown().items():
            demand_by_skill[skill] = demand_by_skill.get(skill, 0) + pw

    result = {}
    for skill, available in net_by_skill.items():
        required = demand_by_skill.get(skill, 0)
        utilisation = required / available if available > 0 else float("inf")
        result[skill] = {
            "available_pw": round(available, 1),
            "required_pw":  round(required, 1),
            "utilisation":  round(utilisation, 2),
            "at_risk":      utilisation > 0.90,
        }
    return result

