@dataclass
class QuarterActuals:
    quarter: str
    committed_count: int
    delivered_count: int
    deferred_in_quarter: int      # projects moved out mid-quarter
    actual_pw_used: float
    planned_pw: float
    actual_budget_usd: float
    planned_budget_usd: float

    @property
    def delivery_rate(self) -> float:
        return self.delivered_count / self.committed_count if self.committed_count else 0.0

    @property
    def capacity_accuracy(self) -> float:
        """1.0 = perfect; < 1.0 = over-estimated available capacity."""
        return self.actual_pw_used / self.planned_pw if self.planned_pw else 0.0

    @property
    def budget_accuracy(self) -> float:
        return self.actual_budget_usd / self.planned_budget_usd if self.planned_budget_usd else 0.0

# Targets:
# delivery_rate >= 0.85 (85 % of committed projects delivered)
# capacity_accuracy 0.80–1.00 (used 80–100 % of planned budget)
# budget_accuracy 0.90–1.10 (within 10 % of budget)

def build_exec_portfolio_summary(
    plan: PortfolioPlan,
    estimates: dict[str, BudgetEstimate],
    scores: dict[str, float],   # request_id → composite score
) -> dict:
    committed_budget = sum(
        estimates[s.request_id].build_cost_usd + estimates[s.request_id].quarterly_opex_usd
        for s in plan.committed if s.request_id in estimates
    )
    return {
        "quarter": plan.quarter,
        "committed_projects": len(plan.committed),
        "deferred_projects": len(plan.deferred),
        "committed_budget_usd": round(committed_budget, 0),
        "capacity_utilisation_pct": round(plan.utilisation_pct, 1),
        "avg_priority_score": round(
            sum(scores.get(s.request_id, 0) for s in plan.committed) / max(len(plan.committed), 1), 2
        ),
        "top_deferred_ids": [s.request_id for s in sorted(
            plan.deferred, key=lambda x: scores.get(x.request_id, 0), reverse=True
        )[:3]],
    }
